import time

class CircuitBreaker:
    def __init__(self, timeout, threshold):
        self.timeout = timeout
        self.threshold = threshold
        self.estado = 'cerrado'
        self.fallos = 0
        self.ultimo_fallo = 0

    def llamar_servicio(self):
        if self.estado == 'cerrado':
            try:
                # Llamar al servicio externo
                pass
            except Exception as e:
                self.fallos += 1
                self.ultimo_fallo = time.time()
                if self.fallos >= self.threshold:
                    self.estado = 'abierto'
        elif self.estado == 'abierto':
            if time.time() - self.ultimo_fallo > self.timeout:
                self.estado = 'medio abierto'
            else:
                raise Exception('Servicio no disponible')
        elif self.estado == 'medio abierto':
            try:
                # Llamar al servicio externo
                pass
                self.estado = 'cerrado'
                self.fallos = 0
            except Exception as e:
                self.estado = 'abierto'

